package controller; import javax.swing.*; import javax.swing.table.*; import util.JapandiTheme; import service.impl.*; import model.CareRecord;
public class CareRecordListFrame extends BaseFrame{ CareRecordServiceImpl service=new CareRecordServiceImpl(); public CareRecordListFrame(){super("照護紀錄",620,720);JPanel p=root();p.add(header("照護紀錄"));DefaultTableModel m=new DefaultTableModel(new String[]{"類型","日期","時間","內容","備註"},0);for(CareRecord r:service.list())m.addRow(new Object[]{r.getType(),r.getDate(),r.getTime(),r.getContent(),r.getNote()});JTable t=new JTable(m);JScrollPane sp=new JScrollPane(t);sp.setBounds(38,105,540,445);p.add(sp);JButton add=JapandiTheme.primary("新增紀錄");add.setBounds(430,570,145,42);add.addActionListener(e->new AddCareRecordFrame().setVisible(true));p.add(add);p.add(bottomNav());} }